import { UsosDialog } from "../dialog";
import { msg } from "@lit/localize";

const _message = msg('Formularz został zmodyfikowany. Czy na pewno chcesz zamknąć ten formularz?');

function _closestCloseable(element: HTMLElement): HTMLElement | Window {
    let parent = element.parentElement;
    while (!(parent instanceof UsosDialog || parent instanceof HTMLBodyElement)) {
        parent = parent!.parentElement;
    }

    return parent instanceof HTMLBodyElement ? window : parent;
}

export function protectForm(form: HTMLFormElement) {
    if (form.dataset.protected === '') return;
    form.dataset.protected = '';

    let protect: boolean;

    form.addEventListener('change', function(){
        form.dataset.dirty = '';
        protect = true;
    });
    form.addEventListener('reset', function(){
        delete form.dataset.dirty;
        protect = false;
    });
    form.addEventListener('submit', function(){
        protect = false;
    });

    // form.submit() does not emit HTMLFormElement:submit event
    form.submit = (function (submitFn) {
        return function (...args) {
            protect = false;
            return submitFn.apply(form, ...args);
        }
    })(form.submit);

    const closeable = _closestCloseable(form);

    const protectFn = function(evt: Event) {
        if (protect && !(form.dataset.protectedPaused === '')) {
            if (confirm(_message)) {
                protect = false;
            } else {
                evt.preventDefault();
            }
        }
    }

    window.addEventListener('beforeunload', function(evt){
        // if form is inside closed UsosDialog then user was warned while closing the dialog
        if (closeable instanceof UsosDialog && !closeable.isOpened()) return;

        protectFn(evt);
    });

    if (closeable instanceof UsosDialog) {
        closeable.addEventListener('dialog:cancel', function(evt){
            protectFn(evt);
        });
    }
}

export function pauseFormProtection(form: HTMLFormElement) {
    form.dataset.protectedPaused = '';
}

export function resumeFormProtection(form: HTMLFormElement) {
    delete form.dataset.protectedPaused;
}
